mapper.select:
select dbo.getCommonName('area', c.area_cd) as areaCd ,b.po_no ,a.proc_order_date ,b.make_No ,b.lot_no ,a.item_cd ,d.item_name ,a.order_qty ,dbo.getCommonName('PROC_STATUS', a.proc_status) as proc_status ,dbo.getCommonName('batch_STATUS', b.batch_status) as batch_status ,a.proc_cd ,c.work_order_id ,b.work_batch_id ,a.work_proc_id from TB_WORK_ORDER_PROC a inner join TB_WORK_ORDER_BATCH b on b.work_batch_id = a.work_batch_id inner join TB_WORK_ORDER_MST c on b.work_order_id = c.work_order_id inner join tb_item_mst d on d.item_cd = a.item_cd where a.proc_cd = 'PRC001'
AND c.area_cd = #{areaCd}
and b.make_No LIKE '%' + #{makeNo} + '%'
and a.item_cd = #{itemCd}
and d.item_name LIKE '%' + #{itemName} + '%'
and a.proc_status = #{procStatus}
ORDER BY c.work_order_date DESC, c.seq DESC

mapper.update:
update TB_WORK_ORDER_PROC
set    etc = #{etc}
where  work_proc_id = #{workProcId}

update TB_WORK_ORDER_PROC
set    proc_status      = #{procStatus}
      ,prod_date        = isnull(CAST(#{prodDate} AS date), CONVERT(date, GETDATE()))
      ,storage_cd       = #{storageCd}
      ,work_start_time  = getdate()
      ,upd_id           = #{userId}
      ,upd_dt           = getDate()
where  work_proc_id     = #{workProcId}

update tb_weigh_info
set     weigh_qty   =#{weighQty}
      , bag_weight =#{bagWeight}
      , test_no    =#{testNo}
      , weigh_yn   =#{weighYn}
      , weigher    =#{weigher}
      , confirmer  =#{confirmer}
      , order_dist =#{orderDist}
      , upd_id     =#{userId}
      ,upd_dt      = getDate()
where weigh_id     = #{weighId}

